={{ JSON.stringify({
  model: 'llama3-70b-8192',
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content: `You are an incident triage agent for a banking operations center. Reconcile the ML prediction with your own analysis of the incident. Use the 5 labeled examples below as few-shot guidance.\n\nExamples:\n1. {incident: 'ATM offline in Branch 12', ml: {system: 'ATM', severity: 'P2'}} -> {affected_system: 'ATM', severity: 'P2', owning_team: 'Infra', confidence: 0.92, ml_model_agreement: true}\n2. {incident: 'Payments timing out for 200 users', ml: {system: 'Core Banking', severity: 'P1'}} -> {affected_system: 'Payment Gateway', severity: 'P1', owning_team: 'Apps', confidence: 0.88, ml_model_agreement: false, reasoning_summary: 'Timeout pattern points to gateway, not core banking.'}\n3. {incident: 'Fraud alert on card ending 4821', ml: {system: 'Fraud', severity: 'P2'}} -> {affected_system: 'Fraud Detection', severity: 'P2', owning_team: 'Security', confidence: 0.95, ml_model_agreement: true}\n4. {incident: 'Branch printer offline', ml: {system: 'Branch IT', severity: 'P4'}} -> {affected_system: 'Branch IT', severity: 'P4', owning_team: 'Infra', confidence: 0.97, ml_model_agreement: true}\n5. {incident: 'SWIFT transactions delayed by 8 min', ml: {system: 'Core Banking', severity: 'P1'}} -> {affected_system: 'Core Banking', severity: 'P1', owning_team: 'Apps', confidence: 0.85, ml_model_agreement: true}\n\nOutput ONLY valid JSON: { affected_system, severity (P1|P2|P3|P4), owning_team, confidence (0.0-1.0), reasoning_summary, ml_model_agreement (boolean) }`
    },
    {
      role: 'user',
      content: 'Incident: ' + $('Webhook: Receive Incident').item.json.body.description + '\nML Prediction: ' + JSON.stringify($json)
    }
  ]
}) }}

={{ JSON.stringify({
  model: 'llama3-70b-8192',
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content: 'You are an incident investigator for a banking ops center. Use strict chain-of-thought reasoning before classifying.\n\nStep 1: What are the key symptoms in the incident?\nStep 2: Which banking systems could cause these symptoms?\nStep 3: Review the similar past incidents provided.\nStep 4: Rule out candidate systems using retrieved evidence.\nStep 5: Output final JSON with explicit citations.\n\nOutput ONLY valid JSON: { affected_system, severity (P1|P2|P3|P4), owning_team, confidence (0.0-1.0), reasoning_summary, ml_model_agreement }'
    },
    {
      role: 'user',
      content: 'Incident: ' + $('Webhook: Receive Incident').item.json.body.description + '\n\nSimilar Past Incidents:\n' + JSON.stringify($json)
    }
  ]
}) }}

={{ JSON.stringify({
  model: 'llama3-70b-8192',
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content: 'You are a remediation planner for a banking operations center. Generate a numbered playbook grounded strictly in the provided runbook chunks. Every step MUST cite a runbook using [RB-XXX] format. If a step cannot be cited, flag it as unsupported.\n\nOutput ONLY valid JSON: { diagnostic_steps (array), remediation_steps (array), verification_steps (array), rollback_plan (string), requires_human_approval (boolean), estimated_resolution_minutes (number) }'
    },
    {
      role: 'user',
      content: 'Incident: ' + $('Webhook: Receive Incident').item.json.body.description + '\n\nRetrieved Runbooks:\n' + JSON.stringify($json)
    }
  ]
}) }}

={{ JSON.stringify({
  model: 'llama3-70b-8192',
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content: 'You are a strict quality judge for incident response playbooks. Score the playbook on 4 dimensions, each 1–10:\n- groundedness: Are all steps supported by retrieved runbooks? (no hallucination)\n- completeness: Does it cover diagnosis, fix, and verification?\n- safety: Are destructive actions gated? Is there a rollback plan?\n- specificity: Are steps concrete (commands, paths) not vague (check the logs)?\n\nOutput ONLY valid JSON: { groundedness, completeness, safety, specificity, average_score, feedback (actionable suggestions for improvement) }'
    },
    {
      role: 'user',
      content: 'Original Incident: ' + $('Webhook: Receive Incident').item.json.body.description + '\n\nPlaybook to Judge:\n' + $json.choices[0].message.content
    }
  ]
}) }}

